using UnityEngine;using System.Collections;
public class CameraShake : MonoBehaviour{public static CameraShake Instance{get;private set;}private Vector3 orig;private Coroutine c;private void Awake(){if(Instance==null)Instance=this;else Destroy(gameObject);}private void Start(){orig=transform.localPosition;}public void Shake(float i,float d){if(c!=null)StopCoroutine(c);c=StartCoroutine(Do(i,d));}private IEnumerator Do(float i,float d){float e=0;while(e<d){e+=Time.deltaTime;float ci=i*(1-e/d);transform.localPosition=orig+new Vector3(Random.Range(-1f,1f)*ci,Random.Range(-1f,1f)*ci,0);yield return null;}transform.localPosition=orig;c=null;}}